import React, { Component } from 'react';
import { styled, createTheme, ThemeProvider } from '@mui/material/styles';
import {
  CssBaseline,
  Box,
  AppBar as MuiAppBar,
  Toolbar,
  Link,
  Container,
  Button
} from '@mui/material';

const AppBar = styled(MuiAppBar)(({ theme }) => ({
  zIndex: theme.zIndex.drawer + 1,
}));

const defaultTheme = createTheme();

export default class Dashboard extends Component {
  constructor(props) {
    super(props);
    this.state = {
      isNightMode: false,
    };
  }

  toggleTheme = () => {
    this.setState((prevState) => ({
      isNightMode: !prevState.isNightMode,
    }));
  };

  render() {

    const { isNightMode, name, email, message } = this.state;

    const projects = [
      {
        title: 'Project 1',
        description: 'Description of project 1.',
        link: 'https://github.com/yourusername/project1',
      },
      {
        title: 'Project 2',
        description: 'Description of project 2.',
        link: 'https://github.com/yourusername/project2',
      },
      // Add more projects as needed
    ];
    return (
      <ThemeProvider theme={defaultTheme}>
        <CssBaseline />
        <Box
          sx={{
            display: 'flex',
            flexDirection: 'column',
            height: '100vh',
            backgroundColor: isNightMode ? '#333' : '#fff',
            color: isNightMode ? '#fff' : '#000',
          }}
        >
          <AppBar position="absolute">
            <Toolbar component="nav" variant="dense" sx={{ justifyContent: 'space-between', overflowX: 'auto' }}>
              <h1>Logo</h1>
              {[
                { title: "About", url: "#about" },
                { title: "Skills", url: "#skills" },
                { title: "Experience", url: "#experience" },
                { title: "Projects", url: "#projects" },
                { title: "Education", url: "#education" },
                { title: "Contact", url: "#contact" }
              ].map((section) => (
                <Link
                  color="inherit"
                  noWrap
                  key={section.title}
                  variant="body2"
                  href={section.url}
                  sx={{ p: 1, flexShrink: 0 }}
                >
                  {section.title}
                </Link>
              ))}
              <Button onClick={this.toggleTheme} variant="contained" color="primary">
                {isNightMode ? 'Switch to Day Mode' : 'Switch to Night Mode'}
              </Button>
            </Toolbar>
          </AppBar>

          <Box component="main" sx={{ flexGrow: 1, overflow: 'auto', padding: 2 }}>
            <Container id="home" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h2" gutterBottom>
                Welcome to My Portfolio
              </Typography>
              <Typography variant="h5">
                I am a passionate web developer.
              </Typography>
            </Container>

            <Container id="about" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h4" gutterBottom>
                About Me
              </Typography>
              <Typography variant="body1">
                I am a passionate web developer with experience in building dynamic and responsive web applications.
                I love coding and enjoy learning new technologies.
              </Typography>
            </Container>

            <Container id="projects" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h4" gutterBottom>
                Projects
              </Typography>
              <Grid container spacing={2}>
                {projects.map((project, index) => (
                  <Grid item xs={12} sm={6} md={4} key={index}>
                    <Card>
                      <CardContent>
                        <Typography variant="h5">{project.title}</Typography>
                        <Typography variant="body2">{project.description}</Typography>
                        <Button href={project.link} target="_blank" variant="contained" color="primary">
                          View Project
                        </Button>
                      </CardContent>
                    </Card>
                  </Grid>
                ))}
              </Grid>
            </Container>

            <Container id="skills" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h4" gutterBottom>
                Skills
              </Typography>
              <Typography variant="body1">
                JavaScript, React, Node.js, HTML, CSS, etc.
              </Typography>
            </Container>

            <Container id="experience" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h4" gutterBottom>
                Experience
              </Typography>
              <Typography variant="body1">
                Previous work experience or internships can be listed here.
              </Typography>
            </Container>

            <Container id="education" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h4" gutterBottom>
                Education
              </Typography>
              <Typography variant="body1">
                Your academic background can be listed here.
              </Typography>
            </Container>

            <Container id="contact" maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
              <Typography variant="h4" gutterBottom>
                Contact Me
              </Typography>
              <form onSubmit={this.handleSubmit}>
                <TextField
                  label="Name"
                  name="name"
                  value={name}
                  onChange={this.handleChange}
                  fullWidth
                  required
                  sx={{ mb: 2 }}
                />
                <TextField
                  label="Email"
                  name="email"
                  type="email"
                  value={email}
                  onChange={this.handleChange}
                  fullWidth
                  required
                  sx={{ mb: 2 }}
                />
                <TextField
                  label="Message"
                  name="message"
                  value={message}
                  onChange={this.handleChange}
                  multiline
                  rows={4}
                  fullWidth
                  required
                  sx={{ mb: 2 }}
                />
                <Button type="submit" variant="contained" color="primary">
                  Send Message
                </Button>
              </form>
            </Container>
          </Box>
        </Box>
      </ThemeProvider>
    );
  }
}
